-- ============================================================
-- 0002_seed_2026.sql  —  migrate the real 2026 league into Supabase
-- Run AFTER 0001_schema.sql.
-- Profiles are backfilled directly so 2026 history exists immediately;
-- link real Auth ids to these by email at first login (see README).
-- ============================================================

  on conflict (year) do nothing;

  on conflict (espn_id) do update set name=excluded.name, world_rank=excluded.world_rank;

  on conflict (season_id, ordinal) do nothing;

  on conflict (email) do nothing;

  on conflict (season_id, profile_id) do nothing;

-- 837 picks, 77 with unresolved golfer ids (golfer_espn_id NULL, name kept for display)
  on conflict (entry_id, tournament_id) do nothing;
